use serde::{Deserialize, Serialize};

use super::player::Player;

// ---------------------------------------------------------------------------
// PlayerMetric enum — generated by macro from a single data table
// ---------------------------------------------------------------------------

macro_rules! define_player_metrics {
    ($(
        $variant:ident : $display:literal => |$player:ident| $expr:expr
    ),* $(,)?) => {
        #[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
        #[serde(rename_all = "SCREAMING_SNAKE_CASE")]
        pub enum PlayerMetric {
            $($variant),*
        }

        impl PlayerMetric {
            /// Human-readable label for this metric.
            pub fn display_name(&self) -> &'static str {
                match self {
                    $(Self::$variant => $display),*
                }
            }

            /// Extract the numeric value from a player record.
            /// Returns `None` when the metric is unavailable.
            pub fn extract(&self, player: &Player) -> Option<f64> {
                match self {
                    $(Self::$variant => { let $player = player; $expr }),*
                }
            }

            /// Return all variants in definition order.
            pub fn all_variants() -> Vec<PlayerMetric> {
                vec![$(Self::$variant),*]
            }
        }
    };
}

