// ---------------------------------------------------------------------------
// Phase
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum Phase {
    InPossession,
    OutOfPossession,
}

// ---------------------------------------------------------------------------
// ArchetypeMetric
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct ArchetypeMetric {
    pub metric: PlayerMetric,
    pub weight: f64,
    pub inverted: bool,
}

// ---------------------------------------------------------------------------
// Archetype
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct Archetype {
    pub id: String,
    pub position: String,
    pub phase: Phase,
    pub name: String,
    pub tags: Vec<String>,
    pub description: String,
    pub metrics: Vec<ArchetypeMetric>,
    pub is_user_created: bool,
}

impl Archetype {
    /// Generate a stable ID: `{position}/{phase}/{name}` in kebab-case.
    pub fn generate_id(position: &str, phase: Phase, name: &str) -> String {
        let phase_str = match phase {
            Phase::InPossession => "in-possession",
            Phase::OutOfPossession => "out-of-possession",
        };
        let name_slug = name.to_lowercase().replace(' ', "-");
        format!(
            "{}/{}/{}",
            position.to_lowercase().replace(' ', "-"),
            phase_str,
            name_slug
        )
    }
}

// ---------------------------------------------------------------------------
// MetricInfo — lightweight descriptor for the UI
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct MetricInfo {
    pub id: PlayerMetric,
    pub display_name: String,
}

