    fn extract_option_u16_fields() {
        let player = sample_player();
        assert_eq!(PlayerMetric::Sprints.extract(&player), Some(45.0));

        // Player with sprints = None
        let no_sprints = Player::default();
        assert_eq!(PlayerMetric::Sprints.extract(&no_sprints), None);
    }

    #[test]
    fn extract_none_for_unavailable_metrics() {
        // Default player has all Option fields = None
        let player = Player::default();
        assert_eq!(PlayerMetric::GoalsPer90.extract(&player), None);
        assert_eq!(PlayerMetric::Rating.extract(&player), Some(0.0)); // non-option, defaults to 0.0
    }

    #[test]
    fn extract_clean_sheets_ratio() {
        // Player with games
        let player = sample_player();
        let expected = Some(6.0 / 20.0); // 6 clean sheets in 20 games
        assert_eq!(PlayerMetric::CleanSheetsRatio.extract(&player), expected);

        // Player with no games
        let no_games = Player::default();
        assert_eq!(PlayerMetric::CleanSheetsRatio.extract(&no_games), None);
    }

